import { getUsers } from "./../.././api/usersAPI"

export function* workerSaga() {
  //@ts-ignore
  const data = yield getUsers()
  console.log(data)
}

export function* watchClikSaga() {
  console.log("rootSaga");
  yield;
}

export function* rootSaga() {
  yield watchClikSaga()
}
